/// <summary>
/// Extension of the <c>NumberSeqModuleInventory</c> class for the ETGSPAIN model.
/// </summary>
[ExtensionOf(classStr(NumberSeqModuleInventory))]
final class NumberSeqModuleInventory_ETGSPAIN_Class_Extension
{
}

Method.Source:
/// <summary>
/// Loads the new number sequence information for ETGSPAIN.
/// </summary>
/// <remarks>
/// Overrides the base method to create a number sequence for <c>ETGSPAINUnsoldJournalId</c>.
/// </remarks>
protected void loadModule()
{
    NumberSeqDatatype datatype = NumberSeqDatatype::construct();

    next loadModule();

    datatype.parmDatatypeId(extendedTypeNum(ETGSPAINUnsoldJournalId));
    datatype.parmReferenceHelp(literalStr("@ETGSPAINLabels:ETGSPAINUnsoldJournalIdNumberSequenceId"));
    datatype.parmWizardIsContinuous(false);
    datatype.parmWizardFetchAheadQty(10);
    datatype.parmWizardIsManual(NoYes::No);
    datatype.parmWizardIsChangeDownAllowed(NoYes::No);
    datatype.parmWizardIsChangeUpAllowed(NoYes::No);
    datatype.addParameterType(NumberSeqParameterType::DataArea, true, false);
    datatype.parmSortField(2000);

    this.create(datatype);
}

/// <summary>
/// Returns the number sequence reference for <c>ETGSPAINUnsoldJournalId</c>.
/// </summary>
/// <returns>
/// Returns a <c>numberSequenceReference</c> for <c>ETGSPAINUnsoldJournalId</c>.
/// </returns>
static numberSequenceReference ETGSPAINnumRefETGSPAINUnsoldJournalId()
{
    return NumberSeqReference::findReference(extendedTypeNum(ETGSPAINUnsoldJournalId));
}
